import 'dart:io';import 'package:flutter/material.dart';import 'package:firebase_auth/firebase_auth.dart';import 'package:cloud_firestore/cloud_firestore.dart';import 'package:intl/intl.dart';import 'package:url_launcher/url_launcher.dart';import 'package:flutter_local_notifications/flutter_local_notifications.dart';import 'package:timezone/timezone.dart' as tz;import 'package:timezone/data/latest.dart' as tz;import 'package:provider/provider.dart';import 'package:shared_preferences/shared_preferences.dart';import 'package:image_picker/image_picker.dart';import 'theme_provider.dart';import 'login.dart';import 'admin_page.dart';class HomeScreen extends StatefulWidget {  const HomeScreen({super.key});  @override  State<HomeScreen> createState() => _HomeScreenState();}class _HomeScreenState extends State<HomeScreen> {  // --- CÁC BIẾN TRẠNG THÁI GIAO DIỆN (UI STATE) ---  int _currentIndex = 0; // Biến lưu index của BottomNavigationBar  bool isVietnamese = true; // Cờ theo dõi ngôn ngữ hiện tại  // --- CÁC CONTROLLER ĐIỀU KHIỂN TEXTFIELD ---  final ScrollController _scrollController = ScrollController();  final TextEditingController _searchController = TextEditingController();  final TextEditingController _chatController = TextEditingController();  // Controllers cho phần Đặt lịch khám  final TextEditingController _nameController = TextEditingController();  final TextEditingController _phoneController = TextEditingController();  final TextEditingController _addressController = TextEditingController();  final TextEditingController _emailController = TextEditingController();  // Controllers cho phần đổi mật khẩu  final TextEditingController _currentPasswordController =      TextEditingController();  final TextEditingController _newPasswordController = TextEditingController();  final TextEditingController _confirmPasswordController =      TextEditingController();  // Controller cho phần đổi tên người dùng  final TextEditingController _editNameController = TextEditingController();  // --- BIẾN NGƯỜI DÙNG & DỮ LIỆU ---  final User? user =      FirebaseAuth.instance.currentUser; // Lấy thông tin user đang đăng nhập  bool _isTyping = false; // Cờ hiệu ứng chatbot đang gõ  // Biến lưu trữ thông tin Hồ sơ cá nhân  String _userName = "";  String _profileImagePath = "";  // Plugin xử lý thông báo Local  final FlutterLocalNotificationsPlugin flutterLocalNotificationsPlugin =      FlutterLocalNotificationsPlugin();  // --- BỘ TỪ ĐIỂN ĐA NGÔN NGỮ (VI - EN) ---  Map<String, dynamic> get lang => {    'home': isVietnamese ? "Trang chủ" : "Home",    'booking': isVietnamese ? "Lịch hẹn" : "Appointment",    'chat': isVietnamese ? "Tin nhắn" : "Message",    'profile': isVietnamese ? "Hồ sơ" : "Profile",    'welcome': isVietnamese ? "Chào bạn! 👋" : "Hello! 👋",    'find_doc': isVietnamese ? "Tìm bác sĩ của bạn" : "Find your doctor",    'search_hint': isVietnamese ? "Tìm bác sĩ..." : "Search doctor...",    'dept': isVietnamese ? "Chuyên khoa" : "Speciality",    'all': isVietnamese ? "Xem tất cả" : "See all",    'book_btn': isVietnamese ? "Bấm để đặt lịch" : "Book now",    'my_booking': isVietnamese ? "Lịch hẹn của bạn" : "Your Appointments",    'no_booking': isVietnamese        ? "Chưa có lịch hẹn nào."        : "No appointments yet.",    'patient': isVietnamese ? "Tên người khám" : "Patient Name",    'phone': isVietnamese ? "Số điện thoại" : "Phone Number",    'address': isVietnamese ? "Địa chỉ" : "Address",    'email': isVietnamese ? "Email" : "Email",    'change_pw': isVietnamese ? "Đổi mật khẩu" : "Change Password",    'logout': isVietnamese ? "Đăng xuất" : "Logout",    'call_hotline': isVietnamese ? "Gọi Hotline" : "Call Hotline",    'chat_hint': isVietnamese ? "Nhập tin nhắn..." : "Type a message...",    'bot_typing': isVietnamese ? "Bác sĩ đang gõ..." : "Doctor is typing...",    'reset_chat': isVietnamese ? "Làm mới chat" : "Reset chat",    'select_hosp': isVietnamese ? "Chọn nơi khám bệnh" : "Select Hospital",    'hosp_title': isVietnamese ? "Danh sách bệnh viện" : "Hospital List",    'back_hosp': isVietnamese ? "Đổi bệnh viện" : "Change Hospital",    'hosp_desc': isVietnamese        ? "Vui lòng chọn bệnh viện để xem bác sĩ"        : "Choose a hospital to see doctors",    'dark_mode': isVietnamese ? "Chế độ tối" : "Dark Mode",    'admin_panel': isVietnamese ? "Trang Quản Trị" : "Admin Panel",    'select_slot': isVietnamese        ? "Chọn ca khám còn trống"        : "Select available slot",    'edit_name': isVietnamese ? "Đổi tên hiển thị" : "Change Name",    'enter_name': isVietnamese ? "Nhập tên mới" : "Enter new name",    'cancel': isVietnamese ? "Hủy" : "Cancel",    'save': isVietnamese ? "Lưu" : "Save",    'name_success': isVietnamese ? "Đổi tên thành công!" : "Name updated!",    'appt_details': isVietnamese ? "Chi tiết lịch hẹn" : "Appointment Details",    'close': isVietnamese ? "Đóng" : "Close",    // Ngôn ngữ cho Đổi Mật Khẩu    'current_pw': isVietnamese ? "Mật khẩu hiện tại" : "Current Password",    'new_pw': isVietnamese ? "Mật khẩu mới" : "New Password",    'confirm_pw': isVietnamese ? "Xác nhận mật khẩu mới" : "Confirm Password",    'pw_not_match': isVietnamese        ? "Mật khẩu xác nhận không khớp!"        : "Passwords do not match!",    'pw_success': isVietnamese        ? "Đổi mật khẩu thành công!"        : "Password changed!",    'pw_error': isVietnamese        ? "Sai mật khẩu hiện tại hoặc lỗi mạng!"        : "Wrong current password or network error!",    'fill_all': isVietnamese        ? "Vui lòng điền đủ thông tin!"        : "Please fill all fields!",  };  // --- CÁC BIẾN LƯU BỘ LỌC TÌM KIẾM ---  String? _selectedHospital;  String? _selectedDeptFilter;  // --- DỮ LIỆU ĐƯỢC TẢI TỪ FIREBASE ---  List<Map<String, dynamic>> bookedAppointments = [];  List<Map<String, dynamic>> _messages = [];  // Danh sách các ca khám mặc định (từ 08:00 đến 22:00)  final List<String> _timeSlots = [    "08:00",    "08:30",    "09:00",    "09:30",    "10:00",    "10:30",    "13:30",    "14:00",    "14:30",    "15:00",    "15:30",    "16:00",    "16:30",    "17:00",    "17:30",    "18:00",    "18:30",    "19:00",    "19:30",    "20:00",    "20:30",    "21:00",    "21:30",    "22:00",  ];  // --- HÀM KHỞI TẠO (CHẠY LẦN ĐẦU KHI VÀO MÀN HÌNH) ---  @override  void initState() {    super.initState();    _resetChat(); // Khởi tạo dữ liệu chatbot    _initNotifications(); // Khởi tạo quyền thông báo    _loadAppState(); // Tải trạng thái ngôn ngữ, tên, ảnh từ bộ nhớ tạm    _fetchAppointments(); // Kéo danh sách lịch hẹn từ Firestore  }  // --- HÀM HỦY (GIẢI PHÓNG BỘ NHỚ KHI ĐÓNG MÀN HÌNH) ---  @override  void dispose() {    _editNameController.dispose();    _currentPasswordController.dispose();    _newPasswordController.dispose();    _confirmPasswordController.dispose();    _nameController.dispose();    _phoneController.dispose();    _addressController.dispose();    _emailController.dispose();    super.dispose();  }  // --- HÀM DỊCH THUẬT & LỌC TÊN CHUYÊN KHOA ---  String _getDisplayName(String name) {    if (isVietnamese) return name;    String key = name.toLowerCase().trim();    // Thuật toán xóa dấu tiếng Việt    key = key.replaceAll(RegExp(r'[àáạảãâầấậẩẫăằắặẳẵ]'), 'a');    key = key.replaceAll(RegExp(r'[èéẹẻẽêềếệểễ]'), 'e');    key = key.replaceAll(RegExp(r'[ìíịỉĩ]'), 'i');    key = key.replaceAll(RegExp(r'[òóọỏõôồốộổỗơờớợởỡ]'), 'o');    key = key.replaceAll(RegExp(r'[ùúụủũưừứựửữ]'), 'u');    key = key.replaceAll(RegExp(r'[ỳýỵỷỹ]'), 'y');    key = key.replaceAll(RegExp(r'[đ]'), 'd');    // Map tên chuyên khoa VN -> EN    Map<String, String> translation = {      "tim mach": "Cardiology",      "mat": "Ophthalmology",      "nhi khoa": "Pediatrics",      "tam than": "Psychiatry",      "chinh hinh": "Orthopedics",      "noi khoa": "Internal Medicine",      "ngoai khoa": "Surgery",      "da lieu": "Dermatology",      "tai mui hong": "ENT",      "rang ham mat": "Dentistry",      "ung buou": "Oncology",      "phu khoa": "Gynecology",      "da khoa": "General Clinic",      "than": "Nephrology",      "tieu hoa": "Gastroenterology",    };    return translation[key] ??        name; // Nếu không có trong map thì giữ nguyên tên gốc  }  // --- HÀM GÁN ICON TỰ ĐỘNG theo TÊN CHUYÊN KHOA ---  IconData _getIconForSpeciality(String name) {    name = name.toLowerCase();    if (name.contains("tim") || name.contains("mạch"))      return Icons.favorite_rounded;    if (name.contains("nhi") || name.contains("trẻ"))      return Icons.child_care_rounded;    if (name.contains("mắt")) return Icons.visibility_rounded;    if (name.contains("tâm thần") || name.contains("não"))      return Icons.psychology_rounded;    if (name.contains("chỉnh hình") || name.contains("xương"))      return Icons.healing_rounded;    if (name.contains("nội")) return Icons.medical_services_rounded;    if (name.contains("ngoại")) return Icons.biotech_rounded;    if (name.contains("da liễu")) return Icons.face_retouching_natural_rounded;    if (name.contains("tai") || name.contains("mũi") || name.contains("họng"))      return Icons.hearing_rounded;    if (name.contains("răng") || name.contains("hàm"))      return Icons.sentiment_satisfied_alt;    return Icons.label_important_outline; // Icon mặc định  }  // --- HÀM NHÓM LỊCH HẸN THEO TỪNG THÁNG CHO TAB LỊCH SỬ ---  Map<String, List<Map<String, dynamic>>> _groupAppointmentsByMonth() {    Map<String, List<Map<String, dynamic>>> groups = {};    List<Map<String, dynamic>> sortedList = List.from(bookedAppointments);    // Sắp xếp lịch hẹn từ mới đến cũ    sortedList.sort(      (a, b) => (b['fullDateTime'] as DateTime).compareTo(        a['fullDateTime'] as DateTime,      ),    );    for (var app in sortedList) {      DateTime date = app['fullDateTime'] as DateTime;      String monthKey = isVietnamese          ? "Tháng ${DateFormat('MM, yyyy').format(date)}"          : DateFormat('MMMM yyyy').format(date);      if (groups[monthKey] == null) groups[monthKey] = [];      groups[monthKey]!.add(app);    }    return groups;  }  // --- HÀM TẢI TRẠNG THÁI NGƯỜI DÙNG TỪ LOCAL STORAGE ---  void _loadAppState() async {    final prefs = await SharedPreferences.getInstance();    setState(() {      isVietnamese = prefs.getBool('isVietnamese') ?? true;      _profileImagePath = prefs.getString('profileImagePath') ?? "";      // Ưu tiên lấy displayName (nếu user đã đổi tên), nếu không lấy tên email mặc định      _userName = user?.displayName != null && user!.displayName!.isNotEmpty          ? user!.displayName!          : (user?.email ?? "User");    });  }  // --- HÀM CHỌN ẢNH ĐẠI DIỆN TỪ THƯ VIỆN THIẾT BỊ ---  Future<void> _pickImage() async {    final ImagePicker picker = ImagePicker();    final XFile? image = await picker.pickImage(source: ImageSource.gallery);    if (image != null) {      final prefs = await SharedPreferences.getInstance();      await prefs.setString(        'profileImagePath',        image.path,      ); // Lưu đường dẫn ảnh vào máy      setState(() {        _profileImagePath = image.path; // Cập nhật lại UI      });    }  }  // --- HÀM XỬ LÝ ĐỔI TÊN NGƯỜI DÙNG ---  Future<void> _editName() async {    // Nếu tên hiện tại đang là email thì clear ô nhập    _editNameController.text = _userName == (user?.email ?? "User")        ? ""        : _userName;    // Hiển thị Dialog đổi tên    final String? newName = await showDialog<String>(      context: context,      builder: (ctx) => AlertDialog(        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),        title: Text(          lang['edit_name'],          style: const TextStyle(fontWeight: FontWeight.bold),        ),        content: TextField(          controller: _editNameController,          autofocus: true,          decoration: InputDecoration(            hintText: lang['enter_name'],            border: OutlineInputBorder(borderRadius: BorderRadius.circular(15)),          ),        ),        actions: [          TextButton(            onPressed: () => Navigator.pop(ctx),            child: Text(              lang['cancel'],              style: const TextStyle(color: Colors.grey),            ),          ),          ElevatedButton(            onPressed: () => Navigator.pop(ctx, _editNameController.text),            style: ElevatedButton.styleFrom(backgroundColor: Colors.blue),            child: Text(              lang['save'],              style: const TextStyle(color: Colors.white),            ),          ),        ],      ),    );    // Cập nhật tên mới lên Firebase Auth và UI    if (newName != null && newName.trim().isNotEmpty) {      try {        await user?.updateDisplayName(newName.trim());        setState(() {          _userName = newName.trim();        });        if (mounted) {          ScaffoldMessenger.of(context).showSnackBar(            SnackBar(              content: Text(lang['name_success']),              backgroundColor: Colors.green,            ),          );        }      } catch (e) {        debugPrint("Lỗi đổi tên: $e");      }    }  }  // --- HÀM XỬ LÝ ĐỔI MẬT KHẨU ---  Future<void> _showChangePasswordDialog() async {    _currentPasswordController.clear();    _newPasswordController.clear();    _confirmPasswordController.clear();    bool isLoading = false;    await showDialog(      context: context,      barrierDismissible: false,      builder: (ctx) => StatefulBuilder(        builder: (context, setDialogState) {          return AlertDialog(            shape: RoundedRectangleBorder(              borderRadius: BorderRadius.circular(20),            ),            title: Text(              lang['change_pw'],              style: const TextStyle(fontWeight: FontWeight.bold),            ),            content: Column(              mainAxisSize: MainAxisSize.min,              children: [                TextField(                  controller: _currentPasswordController,                  obscureText: true, // Ẩn mật khẩu                  decoration: InputDecoration(                    labelText: lang['current_pw'],                    prefixIcon: const Icon(Icons.lock_clock),                    border: OutlineInputBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                ),                const SizedBox(height: 15),                TextField(                  controller: _newPasswordController,                  obscureText: true,                  decoration: InputDecoration(                    labelText: lang['new_pw'],                    prefixIcon: const Icon(Icons.lock_reset),                    border: OutlineInputBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                ),                const SizedBox(height: 15),                TextField(                  controller: _confirmPasswordController,                  obscureText: true,                  decoration: InputDecoration(                    labelText: lang['confirm_pw'],                    prefixIcon: const Icon(Icons.lock_person),                    border: OutlineInputBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                ),              ],            ),            actions: [              TextButton(                onPressed: isLoading ? null : () => Navigator.pop(ctx),                child: Text(                  lang['cancel'],                  style: const TextStyle(color: Colors.grey),                ),              ),              ElevatedButton(                onPressed: isLoading                    ? null                    : () async {                        String currentPw = _currentPasswordController.text                            .trim();                        String newPw = _newPasswordController.text.trim();                        String confirmPw = _confirmPasswordController.text                            .trim();                        // Kiểm tra nhập thiếu                        if (currentPw.isEmpty ||                            newPw.isEmpty ||                            confirmPw.isEmpty) {                          ScaffoldMessenger.of(context).showSnackBar(                            SnackBar(                              content: Text(lang['fill_all']),                              backgroundColor: Colors.orange,                            ),                          );                          return;                        }                        // Kiểm tra mật khẩu xác nhận                        if (newPw != confirmPw) {                          ScaffoldMessenger.of(context).showSnackBar(                            SnackBar(                              content: Text(lang['pw_not_match']),                              backgroundColor: Colors.orange,                            ),                          );                          return;                        }                        setDialogState(                          () => isLoading = true,                        ); // Hiện vòng loading                        try {                          // Bước 1: Yêu cầu Firebase xác thực lại (reauthenticate) bằng mật khẩu cũ                          AuthCredential credential =                              EmailAuthProvider.credential(                                email: user!.email!,                                password: currentPw,                              );                          await user!.reauthenticateWithCredential(credential);                          // Bước 2: Cập nhật mật khẩu mới lên Firebase                          await user!.updatePassword(newPw);                          if (mounted) {                            Navigator.pop(ctx); // Đóng hộp thoại                            ScaffoldMessenger.of(context).showSnackBar(                              SnackBar(                                content: Text(lang['pw_success']),                                backgroundColor: Colors.green,                              ),                            );                          }                        } catch (e) {                          setDialogState(() => isLoading = false);                          if (mounted) {                            ScaffoldMessenger.of(context).showSnackBar(                              SnackBar(                                content: Text(lang['pw_error']),                                backgroundColor: Colors.redAccent,                              ),                            );                          }                          debugPrint("Lỗi đổi mật khẩu: $e");                        }                      },                style: ElevatedButton.styleFrom(backgroundColor: Colors.blue),                child: isLoading                    ? const SizedBox(                        width: 20,                        height: 20,                        child: CircularProgressIndicator(                          color: Colors.white,                          strokeWidth: 2,                        ),                      )                    : Text(                        lang['save'],                        style: const TextStyle(color: Colors.white),                      ),              ),            ],          );        },      ),    );  }  // --- HÀM LẤY DANH SÁCH LỊCH HẸN CỦA BỆNH NHÂN TỪ FIRESTORE ---  void _fetchAppointments() async {    if (user == null) return;    try {      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where(            'userId',            isEqualTo: user?.uid,          ) // Chỉ lấy lịch của user hiện tại          .get();      final List<Map<String, dynamic>> loadedData = snapshot.docs.map((doc) {        final data = doc.data();        return {          'id': doc.id,          'name': data['doctorName'] ?? 'Bác sĩ',          'image': data['image'] ?? 'assets/images/logo.png',          'patient': data['patientName'] ?? 'Bệnh nhân',          'phone': data['patientPhone'] ?? '', // Lấy SĐT          'address': data['patientAddress'] ?? '', // Lấy Địa chỉ          'email': data['patientEmail'] ?? '', // Lấy Email          'hospital': data['hospital'] ?? 'Bệnh viện chưa xác định',          'date': data['date'] ?? '',          'time': data['time'] ?? '',          'dept': data['dept'] ?? '',          'fullDateTime': data['fullDateTime'] != null              ? DateTime.parse(data['fullDateTime'])              : DateTime.now(),        };      }).toList();      setState(() {        bookedAppointments = loadedData;      });    } catch (e) {      debugPrint("Lỗi tải lịch hẹn: $e");    }  }  // --- KHỞI TẠO CẤU HÌNH THÔNG BÁO PUSH NOTIFICATION ---  void _initNotifications() async {    const AndroidInitializationSettings initializationSettingsAndroid =        AndroidInitializationSettings('@mipmap/ic_launcher');    const InitializationSettings initializationSettings =        InitializationSettings(android: initializationSettingsAndroid);    await flutterLocalNotificationsPlugin.initialize(initializationSettings);    // Yêu cầu quyền gửi thông báo trên Android đời mới    final platform = flutterLocalNotificationsPlugin        .resolvePlatformSpecificImplementation<          AndroidFlutterLocalNotificationsPlugin        >();    if (platform != null) {      await platform.requestNotificationsPermission();    }    tz.initializeTimeZones();  }  // --- HÀM GỬI THÔNG BÁO KHI ĐẶT LỊCH THÀNH CÔNG ---  Future<void> _showNotification(    String patientName,    String doctorName,    String time,  ) async {    const AndroidNotificationDetails androidPlatformChannelSpecifics =        AndroidNotificationDetails(          'mediapp_booking_channel',          'Thông báo Mediapp',          importance: Importance.max,          priority: Priority.high,          showWhen: true,          icon: '@mipmap/ic_launcher',        );    const NotificationDetails platformChannelSpecifics = NotificationDetails(      android: androidPlatformChannelSpecifics,    );    await flutterLocalNotificationsPlugin.show(      DateTime.now().millisecond, // ID thông báo (dùng ms để không bị trùng)      isVietnamese          ? 'Mediapp: Đặt lịch thành công! ✅'          : 'Mediapp: Booking Success! ✅',      isVietnamese          ? 'Bệnh nhân $patientName có lịch với $doctorName vào $time'          : 'Patient $patientName has a schedule with $doctorName at $time',      platformChannelSpecifics,    );  }  // --- CÁC HÀM XỬ LÝ CHATBOT AI CƠ BẢN ---  void _resetChat() {    setState(() {      _messages = [        {          "text": isVietnamese              ? "Chào bạn! Tôi là chatbot bác sĩ. Bạn cần hỗ trợ gì?"              : "Hello ! I am your AI Doctor. How can I help you?",          "isMe": false,        },      ];    });  }  void _handleSendMessage() {    String text = _chatController.text.trim();    if (text.isEmpty) return;    // Thêm tin nhắn của User vào danh sách    setState(() {      _messages.add({"text": text, "isMe": true});      _isTyping = true; // Bật cờ chatbot đang gõ    });    _chatController.clear();    // Giả lập thời gian chờ phản hồi của Bot (1.5 giây)    Future.delayed(const Duration(milliseconds: 1500), () {      if (mounted) {        String resp = _getBotResponse(text);        setState(() {          _messages.add({"text": resp, "isMe": false});          _isTyping = false; // Tắt cờ đang gõ        });      }    });  }  String _getBotResponse(String input) {    input = input.toLowerCase();    if (isVietnamese) {      if (input.contains("chào"))        return "Chào bạn! Chúc bạn ngày mới tốt lành.";      return "Bác sĩ đã nhận được thông tin từ bạn!";    } else {      return "Doctor has received your message!";    }  }  // --- HÀM GỌI HOTLINE BẰNG URL LAUNCHER ---  Future<void> _makePhoneCall(String phoneNumber) async {    final Uri launchUri = Uri(scheme: 'tel', path: phoneNumber);    if (await canLaunchUrl(launchUri)) {      await launchUrl(launchUri);    }  }  // --- HÀM XỬ LÝ LÔ GÍC ĐẶT LỊCH (CORE BOOKING LOGIC) ---  Future<void> _bookDoctor(Map<String, dynamic> doc) async {    // 1. Hiển thị bảng chọn Ngày (DatePicker)    final DateTime? d = await showDatePicker(      context: context,      initialDate: DateTime.now(),      firstDate: DateTime.now(),      lastDate: DateTime(2027),    );    if (d == null) return; // Nếu user nhấn Hủy chọn ngày    String dateStr = DateFormat('dd/MM/yyyy').format(d);    // Hiện vòng xoay Loading trong lúc query Firestore    showDialog(      context: context,      barrierDismissible: false,      builder: (ctx) => const Center(child: CircularProgressIndicator()),    );    List<String> takenSlots = [];    try {      // 2. Truy xuất Firestore để tìm các ca khám ĐÃ BỊ ĐẶT của Bác sĩ này trong Ngày này      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where('doctorName', isEqualTo: doc['name'])          .get();      for (var element in snapshot.docs) {        final data = element.data();        if (data['date'] == dateStr) {          takenSlots.add(data['time'].toString()); // Lưu các giờ đã bị chiếm        }      }    } catch (e) {      debugPrint("Lỗi tải ca khám: $e");    }    if (mounted)      Navigator.of(context, rootNavigator: true).pop(); // Tắt Loading    // Clear lại toàn bộ form trước khi mở    _nameController.clear();    _phoneController.clear();    _addressController.clear();    _emailController.clear();    String? selectedTime;    if (!mounted) return;    // 3. Hiển thị BottomSheet chứa danh sách giờ khám và form nhập thông tin    final bool? confirmed = await showModalBottomSheet<bool>(      context: context,      isScrollControlled: true, // Cực kỳ quan trọng để cuộn toàn màn hình      backgroundColor: Colors.transparent,      builder: (ctx) => StatefulBuilder(        builder: (context, setModalState) {          // Hàm kiểm tra form hợp lệ          bool isFormValid =              selectedTime != null &&              _nameController.text.trim().isNotEmpty &&              _phoneController.text.trim().isNotEmpty &&              _addressController.text.trim().isNotEmpty &&              _emailController.text.trim().isNotEmpty;          return Padding(            padding: EdgeInsets.only(              bottom: MediaQuery.of(                ctx,              ).viewInsets.bottom, // Tránh bị bàn phím che            ),            child: Container(              padding: const EdgeInsets.only(top: 20, left: 20, right: 20),              decoration: BoxDecoration(                color: Theme.of(context).scaffoldBackgroundColor,                borderRadius: const BorderRadius.vertical(                  top: Radius.circular(30),                ),              ),              child: SafeArea(                // Dùng SafeArea để tránh bị lẹm thanh Navigation hệ thống                child: Column(                  mainAxisSize: MainAxisSize.min, // Tự động co dãn theo content                  crossAxisAlignment: CrossAxisAlignment.start,                  children: [                    // Thanh gạt mờ trên cùng của BottomSheet                    Center(                      child: Container(                        width: 40,                        height: 5,                        decoration: BoxDecoration(                          color: Colors.grey[300],                          borderRadius: BorderRadius.circular(10),                        ),                      ),                    ),                    const SizedBox(height: 20),                    Text(                      lang['select_slot'],                      style: const TextStyle(                        fontSize: 18,                        fontWeight: FontWeight.bold,                      ),                    ),                    const SizedBox(height: 15),                    // Bọc toàn bộ (Lưới Giờ + Khung Text + Nút Đặt Lịch) vào cuộn để không bị overflow                    Flexible(                      child: SingleChildScrollView(                        child: Padding(                          padding: const EdgeInsets.only(                            bottom: 20,                          ), // Padding nhẹ cho đáy                          child: Column(                            children: [                              // LƯỚI KHUNG GIỜ KHÁM                              Wrap(                                spacing: 10,                                runSpacing: 10,                                children: _timeSlots.map((time) {                                  bool isTaken = takenSlots.contains(time);                                  bool isSelected = selectedTime == time;                                  bool isDark =                                      Theme.of(context).brightness ==                                      Brightness.dark;                                  return ChoiceChip(                                    label: Text(time),                                    selected: isSelected,                                    onSelected: isTaken                                        ? null                                        : (selected) {                                            setModalState(                                              () => selectedTime = time,                                            );                                          },                                    selectedColor: Colors.blue,                                    labelStyle: TextStyle(                                      color: isTaken                                          ? Colors.grey                                          : (isSelected                                                ? Colors.white                                                : (isDark                                                      ? Colors.white                                                      : Colors.blue.shade900)),                                      fontWeight: isSelected                                          ? FontWeight.bold                                          : FontWeight.normal,                                    ),                                    backgroundColor: isTaken                                        ? (isDark                                              ? Colors.grey[800]                                              : Colors.grey[300])                                        : Colors.blue.withOpacity(0.1),                                  );                                }).toList(),                              ),                              const SizedBox(height: 25),                              // BỘ 4 TEXTFIELD NHẬP THÔNG TIN                              _buildBookingTextField(                                controller: _nameController,                                label: lang['patient'],                                icon: Icons.person,                                onChanged: (v) => setModalState(() {}),                              ),                              const SizedBox(height: 15),                              _buildBookingTextField(                                controller: _phoneController,                                label: lang['phone'],                                icon: Icons.phone,                                keyboardType: TextInputType.phone,                                onChanged: (v) => setModalState(() {}),                              ),                              const SizedBox(height: 15),                              _buildBookingTextField(                                controller: _addressController,                                label: lang['address'],                                icon: Icons.location_on,                                onChanged: (v) => setModalState(() {}),                              ),                              const SizedBox(height: 15),                              _buildBookingTextField(                                controller: _emailController,                                label: lang['email'],                                icon: Icons.email,                                keyboardType: TextInputType.emailAddress,                                onChanged: (v) => setModalState(() {}),                              ),                              const SizedBox(height: 25),                              // Nút Xác nhận đặt lịch (Đã được chuyển vào trong SingleChildScrollView)                              SizedBox(                                width: double.infinity,                                height: 55,                                child: ElevatedButton(                                  onPressed: isFormValid                                      ? () =>                                            Navigator.pop(                                              ctx,                                              true,                                            ) // Đóng Sheet và trả về true nếu đủ đk                                      : null, // Disable nếu chưa điền đủ form                                  style: ElevatedButton.styleFrom(                                    backgroundColor: Colors.blue,                                    shape: RoundedRectangleBorder(                                      borderRadius: BorderRadius.circular(15),                                    ),                                  ),                                  child: Text(                                    lang['book_btn'],                                    style: const TextStyle(                                      color: Colors.white,                                      fontWeight: FontWeight.bold,                                      fontSize: 16,                                    ),                                  ),                                ),                              ),                            ],                          ),                        ),                      ),                    ),                  ],                ),              ),            ),          );        },      ),    );    // 4. Nếu user bấm Xác nhận lưu -> Đẩy dữ liệu lên Firebase Firestore    if (confirmed == true && selectedTime != null) {      try {        // Gom ngày và giờ thành 1 biến DateTime đầy đủ để dễ sort sau này        DateTime selDT = DateTime(          d.year,          d.month,          d.day,          int.parse(selectedTime!.split(":")[0]),          int.parse(selectedTime!.split(":")[1]),        );        await FirebaseFirestore.instance.collection('appointments').add({          'userId': user?.uid,          'doctorName': doc['name'],          // Lưu 4 trường thông tin vừa nhập          'patientName': _nameController.text.trim(),          'patientPhone': _phoneController.text.trim(),          'patientAddress': _addressController.text.trim(),          'patientEmail': _emailController.text.trim(),          'hospital': _selectedHospital,          'image': doc['image'],          'date': dateStr,          'time': selectedTime,          'dept': doc['dept'],          'fullDateTime': selDT.toIso8601String(),          'createdAt': FieldValue.serverTimestamp(),        });        _fetchAppointments(); // Làm mới danh sách lịch đã lưu        // Kích hoạt thông báo push local        await _showNotification(          _nameController.text,          doc['name']!,          selectedTime!,        );        if (mounted) {          ScaffoldMessenger.of(context).showSnackBar(            SnackBar(              content: Text(                isVietnamese ? "Đặt lịch thành công!" : "Booking success!",              ),              backgroundColor: Colors.green,            ),          );        }      } catch (e) {        debugPrint("Lỗi đặt lịch: $e");      }    }  }  // --- WIDGET BỔ TRỢ: RENDER TEXTFIELD NHẬP LIỆU ĐẶT LỊCH ---  Widget _buildBookingTextField({    required TextEditingController controller,    required String label,    required IconData icon,    TextInputType keyboardType = TextInputType.text,    required Function(String) onChanged,  }) {    return TextField(      controller: controller,      onChanged: onChanged,      keyboardType: keyboardType,      decoration: InputDecoration(        labelText: label,        prefixIcon: Icon(icon),        filled: true,        fillColor: Theme.of(context).brightness == Brightness.dark            ? Colors.grey[800]            : Colors.grey[100],        border: OutlineInputBorder(          borderRadius: BorderRadius.circular(15),          borderSide: BorderSide.none,        ),      ),    );  }  // --- TAB 3: GIAO DIỆN CHATBOT ---  Widget _buildChatTab() {    return Column(      children: [        // Nút Refresh Chat        Align(          alignment: Alignment.centerRight,          child: TextButton.icon(            onPressed: _resetChat,            icon: const Icon(Icons.refresh, size: 18),            label: Text(lang['reset_chat']),          ),        ),        // Khung hiển thị các đoạn hội thoại        Expanded(          child: ListView.builder(            padding: const EdgeInsets.symmetric(horizontal: 20),            itemCount: _messages.length,            itemBuilder: (context, index) => _ChatBubble(              text: _messages[index]["text"],              isMe: _messages[index]["isMe"],            ),          ),        ),        // Animation trạng thái bot đang gõ        if (_isTyping)          Padding(            padding: const EdgeInsets.only(left: 20, bottom: 10),            child: Align(              alignment: Alignment.centerLeft,              child: Text(                lang['bot_typing'],                style: const TextStyle(                  fontStyle: FontStyle.italic,                  color: Colors.grey,                  fontSize: 12,                ),              ),            ),          ),        _buildChatInputArea(), // Khung nhập text      ],    );  }  // --- KHUNG NHẬP LIỆU TIN NHẮN (DƯỚI CÙNG TAB CHAT) ---  Widget _buildChatInputArea() {    return Container(      padding: const EdgeInsets.all(15),      color: Theme.of(context).scaffoldBackgroundColor,      child: Row(        children: [          Expanded(            child: TextField(              controller: _chatController,              decoration: InputDecoration(                hintText: lang['chat_hint'],                filled: true,                border: OutlineInputBorder(                  borderRadius: BorderRadius.circular(30),                  borderSide: BorderSide.none,                ),              ),            ),          ),          const SizedBox(width: 10),          CircleAvatar(            backgroundColor: Colors.blue,            child: IconButton(              icon: const Icon(Icons.send, color: Colors.white, size: 20),              onPressed: _handleSendMessage,            ),          ),        ],      ),    );  }  // --- TAB 1: GIAO DIỆN TRANG CHỦ (CHÍNH) ---  Widget _buildHomeTab() {    return SingleChildScrollView(      controller: _scrollController,      padding: const EdgeInsets.symmetric(horizontal: 20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          const SizedBox(height: 10),          Text(lang['welcome'], style: const TextStyle(color: Colors.grey)),          // NẾU CHƯA CHỌN BỆNH VIỆN -> HIỂN THỊ DANH SÁCH BỆNH VIỆN          if (_selectedHospital == null) ...[            Text(              lang['select_hosp'],              style: const TextStyle(fontSize: 26, fontWeight: FontWeight.bold),            ),            const SizedBox(height: 8),            Text(              lang['hosp_desc'],              style: const TextStyle(color: Colors.grey, fontSize: 14),            ),            const SizedBox(height: 25),            _buildHospitalGrid(),            // NẾU ĐÃ CHỌN BỆNH VIỆN -> HIỂN THỊ DANH MỤC KHÁM (CHUYÊN KHOA, BÁC SĨ)          ] else ...[            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Expanded(                  child: Text(                    _selectedHospital!,                    style: const TextStyle(                      fontSize: 22,                      fontWeight: FontWeight.bold,                      color: Colors.blue,                    ),                  ),                ),                TextButton.icon(                  onPressed: () => setState(() {                    _selectedHospital = null; // Trả về null để back ra ngoài                    _selectedDeptFilter = null;                  }),                  icon: const Icon(Icons.swap_horiz, size: 18),                  label: Text(lang['back_hosp']),                ),              ],            ),            const SizedBox(height: 15),            _buildSearchBar(), // Thanh tìm kiếm            const SizedBox(height: 20),            // Thanh tiêu đề Khối Chuyên Khoa            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Text(                  lang['dept'],                  style: const TextStyle(                    fontSize: 18,                    fontWeight: FontWeight.bold,                  ),                ),                if (_selectedDeptFilter !=                    null) // Nếu đang lọc chuyên khoa thì hiện nút Xem tất cả                  TextButton(                    onPressed: () => setState(() => _selectedDeptFilter = null),                    child: Text(                      lang['all'],                      style: const TextStyle(fontSize: 12),                    ),                  ),              ],            ),            const SizedBox(height: 10),            _buildCategorySection(), // Khối cuộn ngang các Chuyên khoa            const SizedBox(height: 20),            _buildDoctorGrid(), // Khối Lưới chứa danh sách Bác sĩ          ],          const SizedBox(height: 40),        ],      ),    );  }  // --- WIDGET LƯỚI DANH SÁCH BỆNH VIỆN ---  Widget _buildHospitalGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('hospitals')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (snapshot.hasError)          return const Center(child: Text("Lỗi tải bệnh viện"));        if (!snapshot.hasData)          return const Center(child: CircularProgressIndicator());        final docs = snapshot.data!.docs;        return ListView.builder(          shrinkWrap: true, // Cho bọc trọn trong SingleChildScrollView tổng          physics: const NeverScrollableScrollPhysics(),          itemCount: docs.length,          itemBuilder: (context, i) {            String hospName = docs[i]['name'];            return Container(              margin: const EdgeInsets.only(bottom: 15),              child: InkWell(                onTap: () => setState(                  () => _selectedHospital = hospName,                ), // Đặt biến state để đổi UI                borderRadius: BorderRadius.circular(20),                child: Container(                  padding: const EdgeInsets.all(20),                  decoration: BoxDecoration(                    gradient: LinearGradient(                      colors: [Colors.blue.shade400, Colors.blue.shade700],                      begin: Alignment.topLeft,                      end: Alignment.bottomRight,                    ),                    borderRadius: BorderRadius.circular(20),                    boxShadow: [                      BoxShadow(                        color: Colors.blue.withOpacity(0.3),                        blurRadius: 10,                        offset: const Offset(0, 5),                      ),                    ],                  ),                  child: Row(                    children: [                      Container(                        padding: const EdgeInsets.all(12),                        decoration: const BoxDecoration(                          color: Colors.white24,                          shape: BoxShape.circle,                        ),                        child: const Icon(                          Icons.local_hospital_rounded,                          color: Colors.white,                          size: 30,                        ),                      ),                      const SizedBox(width: 20),                      Expanded(                        child: Column(                          crossAxisAlignment: CrossAxisAlignment.start,                          children: [                            Text(                              hospName,                              style: const TextStyle(                                color: Colors.white,                                fontWeight: FontWeight.bold,                                fontSize: 18,                              ),                            ),                            const SizedBox(height: 4),                            Text(                              isVietnamese                                  ? "Xem danh sách bác sĩ"                                  : "See doctors list",                              style: TextStyle(                                color: Colors.white.withOpacity(0.8),                                fontSize: 13,                              ),                            ),                          ],                        ),                      ),                      const Icon(                        Icons.arrow_forward_ios_rounded,                        color: Colors.white,                        size: 18,                      ),                    ],                  ),                ),              ),            );          },        );      },    );  }  // --- THANH TÌM KIẾM BÁC SĨ ---  Widget _buildSearchBar() => TextField(    decoration: InputDecoration(      hintText: lang['search_hint'],      prefixIcon: const Icon(Icons.search),      filled: true,      border: OutlineInputBorder(        borderRadius: BorderRadius.circular(15),        borderSide: BorderSide.none,      ),    ),  );  // --- WIDGET CUỘN NGANG: CÁC CHUYÊN KHOA ---  Widget _buildCategorySection() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('specialities')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (!snapshot.hasData) return const SizedBox();        final specs = snapshot.data!.docs;        return SizedBox(          height: 100,          child: ListView.builder(            scrollDirection: Axis.horizontal,            itemCount: specs.length,            itemBuilder: (context, i) {              String name = specs[i]['name'];              return _catItem(                _getIconForSpeciality(name), // Lấy icon động                _getDisplayName(name), // Phiên dịch động                name,              );            },          ),        );      },    );  }  // --- ITEM MỘT CHUYÊN KHOA (CIRCLE AVATAR NÚT BẤM) ---  Widget _catItem(IconData icon, String label, String deptKey) =>      GestureDetector(        onTap: () =>            setState(() => _selectedDeptFilter = deptKey), // Gắn bộ lọc        child: Padding(          padding: const EdgeInsets.only(right: 20),          child: Column(            children: [              CircleAvatar(                radius: 28,                backgroundColor: _selectedDeptFilter == deptKey                    ? Colors                          .blue // Đổi màu xanh nếu đang được chọn                    : Colors.blue.withOpacity(0.1),                child: Icon(                  icon,                  color: _selectedDeptFilter == deptKey                      ? Colors.white                      : Colors.blue,                  size: 28,                ),              ),              const SizedBox(height: 8),              Text(                label,                style: TextStyle(                  fontSize: 11,                  fontWeight: _selectedDeptFilter == deptKey                      ? FontWeight.bold                      : FontWeight.w500,                  color: _selectedDeptFilter == deptKey ? Colors.blue : null,                ),              ),            ],          ),        ),      );  // --- WIDGET GRID (LƯỚI): HIỂN THỊ DANH SÁCH BÁC SĨ ---  Widget _buildDoctorGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('doctors')          .orderBy('createdAt', descending: true)          .snapshots(),      builder: (context, snapshot) {        if (snapshot.hasError)          return const Center(            child: Padding(              padding: EdgeInsets.all(20),              child: Text(                "Đang kết nối hệ thống lọc...",                textAlign: TextAlign.center,              ),            ),          );        if (snapshot.connectionState == ConnectionState.waiting)          return const Center(child: CircularProgressIndicator());        final List<DocumentSnapshot> allDocs = snapshot.data!.docs;        // Bọc thêm StreamBuilder của Bệnh Viện để lọc logic Bác sĩ cũ/mới        return StreamBuilder<QuerySnapshot>(          stream: FirebaseFirestore.instance              .collection('hospitals')              .snapshots(),          builder: (ctx, hospSnapshot) {            if (!hospSnapshot.hasData) return const SizedBox();            // Lấy danh sách toàn bộ bệnh viện có trên DB            List<String> registeredHospitals = hospSnapshot.data!.docs                .map(                  (d) => (d.data() as Map<String, dynamic>)['name'].toString(),                )                .toList();            // Thực hiện LỌC (Filter) dữ liệu Bác Sĩ            final filteredDocs = allDocs.where((doc) {              final data = doc.data() as Map<String, dynamic>;              final String doctorHosp = data['hospital'] ?? '';              final String doctorDept = data['dept'] ?? '';              // Xử lý tương thích ngược: Bác sĩ cũ chưa gán bệnh viện hoặc bệnh viện bị xóa              bool isOldDoctor = !registeredHospitals.contains(doctorHosp);              // Bác sĩ mới đã được gán đúng bệnh viện đang được chọn              bool isMatchingNewDoctor = (doctorHosp == _selectedHospital);              // Kiểm tra bộ lọc chuyên khoa              bool matchesDept =                  (_selectedDeptFilter == null) ||                  (doctorDept == _selectedDeptFilter);              return (isOldDoctor || isMatchingNewDoctor) && matchesDept;            }).toList();            if (filteredDocs.isEmpty)              return const Center(                child: Padding(                  padding: EdgeInsets.all(20),                  child: Text("Không có bác sĩ nào phù hợp."),                ),              );            // Render lưới Grid 2 cột            return GridView.builder(              shrinkWrap: true,              physics:                  const NeverScrollableScrollPhysics(), // Không cuộn riêng lẻ              gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(                crossAxisCount: 2,                mainAxisSpacing: 15,                crossAxisSpacing: 15,                childAspectRatio: 0.8, // Tỷ lệ chiều rộng/cao của 1 card bác sĩ              ),              itemCount: filteredDocs.length,              itemBuilder: (ctx, i) {                final data = filteredDocs[i].data() as Map<String, dynamic>;                final doc = {                  'id': filteredDocs[i].id,                  'name': data['name'] ?? '',                  'dept': data['dept'] ?? '',                  'hospital': data['hospital'] ?? '',                  'image': data['image'] ?? '',                };                // Check xem đường dẫn ảnh là từ link web hay từ thư mục assets nội bộ                bool isAsset = !doc['image']!.startsWith('http');                return GestureDetector(                  onTap: () =>                      _bookDoctor(doc), // Kích hoạt hàm Đặt lịch khi bấm vào                  child: Container(                    decoration: BoxDecoration(                      color: Theme.of(context).cardTheme.color ?? Colors.white,                      borderRadius: BorderRadius.circular(15),                      border: Border.all(color: Colors.grey.withOpacity(0.1)),                    ),                    child: Column(                      children: [                        // Phần Hình Ảnh Bác sĩ chiếm nửa trên Card                        Expanded(                          child: ClipRRect(                            borderRadius: const BorderRadius.vertical(                              top: Radius.circular(15),                            ),                            child: isAsset                                ? Image.asset(                                    doc['image']!,                                    fit: BoxFit.cover,                                    width: double.infinity,                                    errorBuilder: (c, e, s) =>                                        const Icon(Icons.person, size: 50),                                  )                                : Image.network(                                    doc['image']!,                                    fit: BoxFit.cover,                                    width: double.infinity,                                    errorBuilder: (c, e, s) =>                                        const Icon(Icons.person, size: 50),                                  ),                          ),                        ),                        // Phần Text tên và chức danh nửa dưới Card                        Padding(                          padding: const EdgeInsets.all(8),                          child: Column(                            children: [                              Text(                                doc['name']!,                                style: const TextStyle(                                  fontWeight: FontWeight.bold,                                  fontSize: 12,                                ),                                textAlign: TextAlign.center,                              ),                              Text(                                _getDisplayName(doc['dept']!),                                style: const TextStyle(                                  color: Colors.grey,                                  fontSize: 10,                                  fontStyle: FontStyle.italic,                                ),                              ),                              const SizedBox(height: 4),                              Text(                                lang['book_btn'],                                style: const TextStyle(                                  color: Colors.blue,                                  fontSize: 10,                                  fontWeight: FontWeight.bold,                                ),                              ),                            ],                          ),                        ),                      ],                    ),                  ),                );              },            );          },        );      },    );  }  // --- HÀM HIỂN THỊ CHI TIẾT LỊCH HẸN KHI BẤM VÀO LỊCH SỬ ---  void _showAppointmentDetails(Map<String, dynamic> app) {    showModalBottomSheet(      context: context,      isScrollControlled: true, // Cho phép kéo bảng cao lên nếu thông tin dài      shape: const RoundedRectangleBorder(        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),      ),      builder: (ctx) {        return SafeArea(          // Bảo vệ không bị lẹm thanh công cụ dưới cùng          child: Container(            padding: const EdgeInsets.only(              top: 20,              left: 20,              right: 20,              bottom: 20,            ),            // Khống chế chiều cao tối đa của popup là 85% màn hình để trông đẹp mắt            constraints: BoxConstraints(              maxHeight: MediaQuery.of(context).size.height * 0.85,            ),            child: Column(              mainAxisSize: MainAxisSize.min,              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Center(                  child: Container(                    width: 40,                    height: 5,                    decoration: BoxDecoration(                      color: Colors.grey[300],                      borderRadius: BorderRadius.circular(10),                    ),                  ),                ),                const SizedBox(height: 20),                Text(                  lang['appt_details'],                  style: const TextStyle(                    fontSize: 20,                    fontWeight: FontWeight.bold,                    color: Colors.blue,                  ),                ),                const SizedBox(height: 15),                // Bọc vào Flexible + SingleChildScrollView để nếu Email hay Tên quá dài thì sẽ tự tạo thanh cuộn                Flexible(                  child: SingleChildScrollView(                    child: Column(                      children: [                        // Thông tin Bác sĩ                        _detailRow(                          Icons.medical_services,                          "Bác sĩ / Doctor",                          app['name'],                        ),                        _detailRow(                          Icons.category,                          lang['dept'],                          _getDisplayName(app['dept']),                        ),                        _detailRow(                          Icons.local_hospital,                          lang['select_hosp'],                          app['hospital'],                        ),                        _detailRow(                          Icons.access_time,                          "Thời gian / Time",                          "${app['time']} - ${app['date']}",                        ),                        const Divider(height: 30),                        // Thông tin Bệnh nhân (với tính năng tự động xuống dòng softWrap)                        _detailRow(                          Icons.person,                          lang['patient'],                          app['patient'],                        ),                        if (app['phone'].toString().isNotEmpty)                          _detailRow(Icons.phone, lang['phone'], app['phone']),                        if (app['email'].toString().isNotEmpty)                          _detailRow(Icons.email, lang['email'], app['email']),                        if (app['address'].toString().isNotEmpty)                          _detailRow(                            Icons.location_on,                            lang['address'],                            app['address'],                          ),                      ],                    ),                  ),                ),                const SizedBox(height: 20),                // NÚT ĐÓNG BẢNG CHI TIẾT                SizedBox(                  width: double.infinity,                  height: 50,                  child: ElevatedButton(                    onPressed: () => Navigator.pop(ctx),                    style: ElevatedButton.styleFrom(                      backgroundColor: Colors.blue,                      shape: RoundedRectangleBorder(                        borderRadius: BorderRadius.circular(15),                      ),                    ),                    child: Text(                      lang['close'],                      style: const TextStyle(                        color: Colors.white,                        fontWeight: FontWeight.bold,                        fontSize: 16,                      ),                    ),                  ),                ),              ],            ),          ),        );      },    );  }  // --- WIDGET BỔ TRỢ: DÒNG THÔNG TIN CHI TIẾT CÓ HỖ TRỢ XUỐNG DÒNG ---  Widget _detailRow(IconData icon, String title, String value) {    return Padding(      padding: const EdgeInsets.only(bottom: 12),      child: Row(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Icon(icon, size: 20, color: Colors.grey),          const SizedBox(width: 10),          Expanded(            child: Column(              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Text(                  title,                  style: const TextStyle(fontSize: 12, color: Colors.grey),                ),                // Thêm softWrap: true để chữ tự tràn xuống dòng dưới nếu dài quá, ko bị lỗi lẹm viền                Text(                  value,                  style: const TextStyle(                    fontSize: 15,                    fontWeight: FontWeight.w500,                  ),                  softWrap: true,                ),              ],            ),          ),        ],      ),    );  }  // --- TAB 2: LỊCH SỬ CÁC CUỘC HẸN ---  Widget _buildHistoryTab() {    final groupedData =        _groupAppointmentsByMonth(); // Nhóm dữ liệu theo tháng trước khi render    return Padding(      padding: const EdgeInsets.all(20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text(            lang['my_booking'],            style: const TextStyle(              fontSize: 22,              fontWeight: FontWeight.bold,              color: Colors.blue,            ),          ),          const SizedBox(height: 15),          Expanded(            child: bookedAppointments.isEmpty                ? Center(child: Text(lang['no_booking'])) // Khi chưa có lịch                : ListView.builder(                    itemCount: groupedData.length,                    itemBuilder: (context, index) {                      String month = groupedData.keys.elementAt(                        index,                      ); // Lấy tên Tháng                      List<Map<String, dynamic>> apps = groupedData[month]!;                      return Column(                        crossAxisAlignment: CrossAxisAlignment.start,                        children: [                          // Thanh Header hiển thị Tháng                          Padding(                            padding: const EdgeInsets.symmetric(vertical: 10),                            child: Row(                              children: [                                Container(                                  padding: const EdgeInsets.symmetric(                                    horizontal: 12,                                    vertical: 6,                                  ),                                  decoration: BoxDecoration(                                    color: Colors.blue.withOpacity(0.1),                                    borderRadius: BorderRadius.circular(20),                                  ),                                  child: Text(                                    month,                                    style: const TextStyle(                                      fontWeight: FontWeight.bold,                                      color: Colors.blue,                                      fontSize: 14,                                    ),                                  ),                                ),                                const Expanded(child: Divider(indent: 10)),                              ],                            ),                          ),                          // List danh sách lịch hẹn trong tháng đó                          ...apps.map((app) {                            bool isAsset = !app['image'].startsWith('http');                            return Card(                              margin: const EdgeInsets.only(bottom: 10),                              elevation: 2,                              shape: RoundedRectangleBorder(                                borderRadius: BorderRadius.circular(15),                              ),                              child: ListTile(                                onTap: () => _showAppointmentDetails(                                  app,                                ), // Gọi form hiển thị chi tiết khi bấm                                leading: CircleAvatar(                                  backgroundImage: isAsset                                      ? AssetImage(app['image'])                                            as ImageProvider                                      : NetworkImage(app['image']),                                ),                                title: Text(                                  app['name'],                                  style: const TextStyle(                                    fontWeight: FontWeight.bold,                                  ),                                ),                                subtitle: Text(                                  "${lang['patient']}: ${app['patient']}\n🏢 ${app['hospital']}\n📅 ${app['date']} - ${app['time']}",                                  style: const TextStyle(fontSize: 12),                                ),                                isThreeLine: true,                                trailing: IconButton(                                  icon: const Icon(                                    Icons.delete_outline,                                    color: Colors.redAccent,                                  ),                                  onPressed: () async {                                    // Chức năng XÓA Lịch Hẹn                                    await FirebaseFirestore.instance                                        .collection('appointments')                                        .doc(app['id'])                                        .delete();                                    _fetchAppointments(); // Refresh lại danh sách                                  },                                ),                              ),                            );                          }).toList(), // Chuyển đổi list map sang dạng list Widget                        ],                      );                    },                  ),          ),        ],      ),    );  }  // --- TAB 4: HỒ SƠ CÁ NHÂN & CÀI ĐẶT ---  Widget _buildProfileTab() {    final themeProvider = Provider.of<ThemeProvider>(      context,    ); // Đọc theme global    final isDark = themeProvider.isDarkMode;    return SingleChildScrollView(      padding: const EdgeInsets.all(20),      child: Column(        children: [          // KHỐI 1: HEADER THÔNG TIN NGƯỜI DÙNG (AVATAR + TÊN)          Container(            padding: const EdgeInsets.all(20),            decoration: BoxDecoration(              color: isDark ? Colors.grey[800] : Colors.white,              borderRadius: BorderRadius.circular(25),              boxShadow: [                BoxShadow(                  color: Colors.blue.withOpacity(0.1),                  blurRadius: 20,                  offset: const Offset(0, 10),                ),              ],            ),            child: Column(              children: [                // Khối Stack bọc Hình đại diện + Icon Camera                Stack(                  alignment: Alignment.bottomRight,                  children: [                    Container(                      decoration: BoxDecoration(                        shape: BoxShape.circle,                        border: Border.all(                          color: Colors.blue.shade100,                          width: 4,                        ),                      ),                      child: CircleAvatar(                        radius: 50,                        backgroundColor: Colors.blue.shade50,                        backgroundImage: _profileImagePath.isNotEmpty                            ? FileImage(                                File(_profileImagePath),                              ) // Load ảnh từ điện thoại nếu có                            : null,                        child: _profileImagePath.isEmpty                            ? Icon(                                Icons.person,                                size: 50,                                color: Colors.blue.shade300,                              )                            : null,                      ),                    ),                    GestureDetector(                      onTap: _pickImage, // Chạm để mở thư viện ảnh                      child: Container(                        padding: const EdgeInsets.all(8),                        decoration: BoxDecoration(                          color: Colors.blue,                          shape: BoxShape.circle,                          border: Border.all(color: Colors.white, width: 2),                        ),                        child: const Icon(                          Icons.camera_alt,                          size: 16,                          color: Colors.white,                        ),                      ),                    ),                  ],                ),                const SizedBox(height: 15),                // Khối Tên + Icon Edit                Row(                  mainAxisAlignment: MainAxisAlignment.center,                  children: [                    Text(                      _userName,                      style: const TextStyle(                        fontSize: 22,                        fontWeight: FontWeight.bold,                      ),                    ),                    const SizedBox(width: 8),                    GestureDetector(                      onTap: _editName, // Chạm để gọi hàm Update tên                      child: const Icon(                        Icons.edit_square,                        color: Colors.blue,                        size: 18,                      ),                    ),                  ],                ),                const SizedBox(height: 5),                Text(                  user?.email ?? "User",                  style: const TextStyle(fontSize: 14, color: Colors.grey),                ),              ],            ),          ),          const SizedBox(height: 30),          // KHỐI 2: MENU CHỨC NĂNG & CÀI ĐẶT          Container(            decoration: BoxDecoration(              color: isDark ? Colors.grey[800] : Colors.white,              borderRadius: BorderRadius.circular(25),              boxShadow: [                BoxShadow(                  color: Colors.grey.withOpacity(0.05),                  blurRadius: 20,                  offset: const Offset(0, 10),                ),              ],            ),            child: Column(              children: [                // Menu Switch Theme                ListTile(                  contentPadding: const EdgeInsets.symmetric(                    horizontal: 20,                    vertical: 5,                  ),                  leading: Container(                    padding: const EdgeInsets.all(10),                    decoration: BoxDecoration(                      color: Colors.amber.withOpacity(0.15),                      shape: BoxShape.circle,                    ),                    child: Icon(                      isDark ? Icons.dark_mode : Icons.light_mode,                      color: Colors.amber,                    ),                  ),                  title: Text(                    lang['dark_mode'],                    style: const TextStyle(fontWeight: FontWeight.w600),                  ),                  trailing: Switch(                    value: isDark,                    activeColor: Colors.blue,                    onChanged: (v) => themeProvider.toggleTheme(),                  ),                ),                // Menu Trang Quản trị (Chỉ hiện khi email khớp 100%)                if (user?.email == "quocthang15082004@gmail.com") ...[                  _buildMenuDivider(),                  _buildModernMenu(                    Icons.admin_panel_settings,                    lang['admin_panel'],                    Colors.indigo,                    () {                      Navigator.push(                        context,                        MaterialPageRoute(                          builder: (c) => AdminPage(isVietnamese: isVietnamese),                        ),                      );                    },                  ),                ],                _buildMenuDivider(),                // Menu Đổi mật khẩu                _buildModernMenu(                  Icons.lock_outline,                  lang['change_pw'],                  Colors.green,                  () {                    _showChangePasswordDialog(); // Gọi Form đổi MK                  },                ),                _buildMenuDivider(),                // Menu Đăng xuất (Tô đỏ)                _buildModernMenu(                  Icons.logout,                  lang['logout'],                  Colors.redAccent,                  () async {                    await FirebaseAuth.instance                        .signOut(); // Xóa phiên session Firebase                    Navigator.pushReplacement(                      context,                      MaterialPageRoute(builder: (c) => Login()),                    );                  },                  isRed: true,                ),              ],            ),          ),          const SizedBox(height: 20),        ],      ),    );  }  // --- WIDGET BỔ TRỢ: Kẻ gạch ngang giữa các dòng Menu ---  Widget _buildMenuDivider() {    return Padding(      padding: const EdgeInsets.symmetric(horizontal: 20),      child: Divider(color: Colors.grey.withOpacity(0.2), height: 1),    );  }  // --- WIDGET BỔ TRỢ: Render một dòng Menu chuẩn hiện đại ---  Widget _buildModernMenu(    IconData icon,    String title,    Color iconColor,    VoidCallback onTap, {    bool isRed = false, // Cờ hiệu để tô đỏ (Dành riêng cho Log Out)  }) {    return ListTile(      contentPadding: const EdgeInsets.symmetric(horizontal: 20, vertical: 5),      leading: Container(        padding: const EdgeInsets.all(10),        decoration: BoxDecoration(          color: isRed              ? Colors.red.withOpacity(0.1)              : iconColor.withOpacity(0.15),          shape: BoxShape.circle,        ),        child: Icon(icon, color: isRed ? Colors.redAccent : iconColor),      ),      title: Text(        title,        style: TextStyle(          fontWeight: FontWeight.w600,          color: isRed ? Colors.redAccent : null,        ),      ),      trailing: const Icon(        Icons.arrow_forward_ios,        size: 16,        color: Colors.grey,      ),      onTap: onTap,    );  }  // --- HÀM RENDER NỘI DUNG CHÍNH THEO INDEX CỦA BOTTOM BAR ---  Widget _getBody() {    switch (_currentIndex) {      case 0:        return _buildHomeTab();      case 1:        return _buildHistoryTab();      case 2:        return _buildChatTab();      case 3:        return _buildProfileTab();      default:        return _buildHomeTab();    }  }  // --- HÀM BUILD GIAO DIỆN CHÍNH (SCAFFOLD TỔNG) ---  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(        title: const Text(          "Mediapp",          style: TextStyle(color: Colors.blue, fontWeight: FontWeight.bold),        ),        backgroundColor: Theme.of(context).appBarTheme.backgroundColor,        elevation: 0,        actions: [          // Nút gọi điện khẩn cấp          IconButton(            icon: const Icon(Icons.phone, color: Colors.red),            onPressed: () => _makePhoneCall("19001234"),          ),          // Nút chuyển đổi ngôn ngữ Anh / Việt          TextButton(            onPressed: () async {              setState(() => isVietnamese = !isVietnamese);              final prefs = await SharedPreferences.getInstance();              await prefs.setBool(                'isVietnamese',                isVietnamese,              ); // Lưu vô bộ nhớ đệm              _resetChat(); // Reset chat để dịch lại mảng chat            },            child: Text(              isVietnamese ? "EN" : "VN",              style: const TextStyle(                color: Colors.blue,                fontWeight: FontWeight.bold,              ),            ),          ),        ],      ),      body: _getBody(), // Thân của App, gọi hàm _getBody() bên trên      bottomNavigationBar: BottomNavigationBar(        currentIndex: _currentIndex,        onTap: (v) => setState(() => _currentIndex = v), // Chuyển Tab        selectedItemColor: Colors.blue,        unselectedItemColor: Colors.grey,        type: BottomNavigationBarType.fixed,        items: [          BottomNavigationBarItem(            icon: const Icon(Icons.home),            label: lang['home'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.calendar_today),            label: lang['booking'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.message),            label: lang['chat'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.person),            label: lang['profile'],          ),        ],      ),    );  }}// --- WIDGET ĐỘC LẬP: GIAO DIỆN BONG BÓNG CHAT ---class _ChatBubble extends StatelessWidget {  final String text;  final bool isMe;  const _ChatBubble({required this.text, required this.isMe});  @override  Widget build(BuildContext context) {    return Align(      // Canh trái / phải tùy theo người gửi là User (Me) hay Chatbot      alignment: isMe ? Alignment.centerRight : Alignment.centerLeft,      child: Container(        margin: const EdgeInsets.symmetric(vertical: 5),        padding: const EdgeInsets.all(12),        decoration: BoxDecoration(          color: isMe              ? Colors                    .blue // Nền xanh cho tin nhắn User              : (Theme.of(context).brightness == Brightness.dark                    ? Colors.grey[800] // Nền xám đen cho Bot ở Dark Mode                    : Colors                          .grey                          .shade200), // Nền xám nhạt cho Bot ở Light Mode          borderRadius: BorderRadius.circular(15),        ),        child: Text(          text,          style: TextStyle(            color: isMe                ? Colors.white                : (Theme.of(context).brightness == Brightness.dark                      ? Colors.white                      : Colors.black),          ),        ),      ),    );  }}